mapper.select:
select count(1)
from campus_student_course
where student_id = #{studentId}
  and section_id = #{sectionId}
  and status = '0'

mapper.update:
update campus_student_course
set status = '1'
where student_id = #{studentId}
  and section_id = #{sectionId}
  and status = '0'

mapper.select:
select count(1)
from campus_course_section s
    inner join campus_teacher t on t.teacher_id = s.teacher_id
where t.user_id = #{userId}
  and s.section_id = #{sectionId}

select count(1)
from campus_student_course
where section_id = #{sectionId}
  and student_id = #{studentId}
  and status = '0'

mapper.update:
update campus_score
set score = #{score},
    grade_point = #{gradePoint},
    exam_type = #{examType}
where student_id = #{studentId}
  and section_id = #{sectionId}
